// ================== FETCH POKEMON ==================
async function getPokemon(name) {
  const res = await fetch(`https://pokeapi.co/api/v2/pokemon/${name.toLowerCase()}`);
  if (!res.ok) throw new Error("Pokemon not found");
  const data = await res.json();
  const hp = data.stats.find(s => s.stat.name === "hp").base_stat;

  // Fetch actual move data for first 4 moves
  const moveNames = data.moves.slice(0, 4).map(m => m.move.name);
  const moves = await Promise.all(moveNames.map(async m => {
    try {
      const r = await fetch(`https://pokeapi.co/api/v2/move/${m}`);
      const d = await r.json();
      return {
        name: d.name.replace(/-/g, " "),
        key: d.name,
        power: d.power || 35,
        accuracy: d.accuracy || 100,
        damageClass: d.damage_class?.name || "physical",
        type: d.type?.name || "normal"
      };
    } catch { return { name: m, key: m, power: 35, accuracy: 100, damageClass: "physical", type: "normal" }; }
  }));

  return {
    name: data.name,
    hp, maxHp: hp,
    attack: data.stats.find(s => s.stat.name === "attack").base_stat,
    defense: data.stats.find(s => s.stat.name === "defense").base_stat,
    specialAttack: data.stats.find(s => s.stat.name === "special-attack").base_stat,
    speed: data.stats.find(s => s.stat.name === "speed").base_stat,
    moves,
    sprite: data.sprites.front_default,
    spriteBack: data.sprites.back_default,
    type: "pokemon"
  };
}

// ================== DAMAGE ==================
function calculateDamage(attacker, defender, move) {
  const level = 50;
  const atkStat = move.damageClass === "special" ? attacker.specialAttack : attacker.attack;
  // Increased divisor (200 instead of 50) to significantly reduce damage per hit
  let base = (((2 * level / 5 + 2) * move.power * atkStat / defender.defense) / 200) + 2;
  let random = Math.random() * (1 - 0.85) + 0.85;
  let damage = Math.floor(base * random);
  // Cap damage at 20% of defender's max HP so battles last at least 5 turns
  const cap = Math.floor(defender.maxHp * 0.20);
  return Math.min(damage, cap);
}

// ================== GAME STATE ==================
let player, enemy;

// ================== UI ==================
function updateUI() {
  document.getElementById("playerName").innerText = player.name.toUpperCase();
  document.getElementById("enemyName").innerText = enemy.name.toUpperCase();
  document.getElementById("playerHPText").innerText = `HP: ${player.hp}/${player.maxHp}`;
  document.getElementById("enemyHPText").innerText = `HP: ${enemy.hp}/${enemy.maxHp}`;

  const playerPct = player.hp / player.maxHp * 100;
  const enemyPct = enemy.hp / enemy.maxHp * 100;

  const pb = document.getElementById("playerHP");
  const eb = document.getElementById("enemyHP");
  pb.style.width = playerPct + "%";
  eb.style.width = enemyPct + "%";
  pb.style.background = playerPct > 50 ? "green" : playerPct > 20 ? "orange" : "red";
  eb.style.background = enemyPct > 50 ? "green" : enemyPct > 20 ? "orange" : "red";

  document.getElementById("playerStats").innerText =
    `ATK: ${player.attack}  SP.ATK: ${player.specialAttack}  SPD: ${player.speed}`;
  document.getElementById("enemyStats").innerText =
    `ATK: ${enemy.attack}  SP.ATK: ${enemy.specialAttack}  SPD: ${enemy.speed}`;
}

// ================== RENDER MOVE BUTTONS ==================
function renderMoveButtons() {
  const menu = document.getElementById("moveMenu");
  menu.innerHTML = "";
  player.moves.forEach((move, i) => {
    const btn = document.createElement("div");
    btn.className = "move-btn";
    btn.id = `moveBtn${i}`;
    const tag = move.damageClass === "special" ? "✨" : "⚔️";
    btn.innerHTML = `<span class="move-name">${move.name.toUpperCase()}</span><span class="move-tag">${tag} PWR:${move.power}</span>`;
    btn.onclick = () => useMove(i);
    menu.appendChild(btn);
  });
}

function setMoveBtnsDisabled(disabled) {
  player.moves.forEach((_, i) => {
    const btn = document.getElementById(`moveBtn${i}`);
    if (btn) btn.classList.toggle("disabled", disabled);
  });
}

// ================== USE MOVE ==================
async function useMove(moveIndex) {
  if (player.hp <= 0 || enemy.hp <= 0) return;
  setMoveBtnsDisabled(true);

  const move = player.moves[moveIndex];
  let log = "";

  // Check accuracy
  if (Math.random() * 100 > move.accuracy) {
    log += `${player.name} used <b>${move.name.toUpperCase()}</b> but missed!<br>`;
  } else {
    const damage = calculateDamage(player, enemy, move);
    enemy.hp = Math.max(0, enemy.hp - damage);
    const tag = move.damageClass === "special" ? "✨ special" : "⚔️ physical";
    log += `${player.name} used <b>${move.name.toUpperCase()}</b> <i>(${tag})</i>! (-${damage} HP)<br>`;
  }

  // Enemy turn — picks a random move
  if (enemy.hp > 0) {
    const enemyMove = enemy.moves[Math.floor(Math.random() * enemy.moves.length)];
    if (Math.random() * 100 > enemyMove.accuracy) {
      log += `${enemy.name} used <b>${enemyMove.name.toUpperCase()}</b> but missed!`;
    } else {
      const eDamage = calculateDamage(enemy, player, enemyMove);
      player.hp = Math.max(0, player.hp - eDamage);
      const eTag = enemyMove.damageClass === "special" ? "✨ special" : "⚔️ physical";
      log += `${enemy.name} used <b>${enemyMove.name.toUpperCase()}</b> <i>(${eTag})</i>! (-${eDamage} HP)`;
    }
  }

  updateUI();

  if (player.hp <= 0) log += "<br><b>You fainted! 💀</b>";
  else if (enemy.hp <= 0) log += "<br><b>Enemy fainted! 🎉</b>";
  else setMoveBtnsDisabled(false);

  document.getElementById("textBox").innerHTML = log;
}

// ================== RUN ==================
const DEMON_SCREAM_B64 = "";
function run() {
  document.getElementById("textBox").innerText = "You ran away! 🏃";
  setMoveBtnsDisabled(true);

  const scream = new Audio("data:audio/mp3;base64," + DEMON_SCREAM_B64);
  scream.volume = 1.0;
  scream.play().catch(() => { });

  document.getElementById("runOverlay").style.display = "flex";
}

// ================== START ==================
async function startBattle() {
  document.getElementById("textBox").innerText = "Loading battle...";
  player = await getPokemon("charmander");
  enemy = await getPokemon("pikachu");
  document.getElementById("playerSprite").src = player.spriteBack || player.sprite;
  document.getElementById("enemySprite").src = enemy.sprite;
  updateUI();
  renderMoveButtons();
  document.getElementById("textBox").innerText = "A wild " + enemy.name.toUpperCase() + " appeared!";
}

startBattle();

// ================== POKEMON PICKER ==================

let allPokemon = [];        // [{name, id, sprite}]
let filteredPokemon = [];
let selectingFor = 'player'; // 'player' or 'enemy'
let pickerSelections = { player: null, enemy: null };

async function loadPokedex() {
  if (allPokemon.length > 0) return; // already loaded
  try {
    const res = await fetch('https://pokeapi.co/api/v2/pokemon?limit=1025');
    const data = await res.json();
    allPokemon = data.results.map((p, i) => {
      const id = i + 1;
      return {
        name: p.name,
        id,
        sprite: `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${id}.png`
      };
    });
    filteredPokemon = [...allPokemon];
  } catch (e) {
    document.getElementById('pokedexGrid').innerHTML = '<div class="poke-loading">Failed to load Pokédex. Check connection.</div>';
  }
}

function renderPokedexGrid() {
  const grid = document.getElementById('pokedexGrid');
  const count = document.getElementById('pokeCount');
  count.textContent = `${filteredPokemon.length} Pokémon`;

  if (filteredPokemon.length === 0) {
    grid.innerHTML = '<div class="poke-loading">No Pokémon found.</div>';
    return;
  }

  grid.innerHTML = '';
  const playerName = pickerSelections.player?.name;
  const enemyName = pickerSelections.enemy?.name;

  filteredPokemon.forEach(p => {
    const card = document.createElement('div');
    card.className = 'poke-card';
    if (p.name === playerName) card.classList.add('selected-player');
    if (p.name === enemyName) card.classList.add('selected-enemy');

    card.innerHTML = `
      <img src="${p.sprite}" alt="${p.name}" loading="lazy" />
      <div class="poke-card-name">${p.name.replace(/-/g, ' ')}</div>
      <div class="poke-card-num">#${String(p.id).padStart(3, '0')}</div>
    `;
    card.addEventListener('click', () => selectPokemon(p));
    grid.appendChild(card);
  });
}

function filterPokedex() {
  const q = document.getElementById('pokeSearch').value.toLowerCase().trim();
  filteredPokemon = q
    ? allPokemon.filter(p => p.name.includes(q) || String(p.id).includes(q))
    : [...allPokemon];
  renderPokedexGrid();
}

function selectPokemon(p) {
  pickerSelections[selectingFor] = p;
  updateSelectedDisplay();
  renderPokedexGrid();

  // Auto-switch to other side if it's empty
  if (selectingFor === 'player' && !pickerSelections.enemy) {
    selectingFor = 'enemy';
    updateSelectingForUI();
  } else if (selectingFor === 'enemy' && !pickerSelections.player) {
    selectingFor = 'player';
    updateSelectingForUI();
  }
}

function updateSelectedDisplay() {
  const pSide = document.getElementById('playerSelectedCard');
  const eSide = document.getElementById('enemySelectedCard');
  const pp = pickerSelections.player;
  const ep = pickerSelections.enemy;

  document.getElementById('playerPreview').src = pp ? pp.sprite : '';
  document.getElementById('playerPreviewName').textContent = pp ? pp.name.toUpperCase() : 'None selected';
  document.getElementById('enemyPreview').src = ep ? ep.sprite : '';
  document.getElementById('enemyPreviewName').textContent = ep ? ep.name.toUpperCase() : 'None selected';

  pSide.classList.toggle('active-selection', selectingFor === 'player');
  eSide.classList.toggle('active-selection', selectingFor === 'enemy');
}

function updateSelectingForUI() {
  const badge = document.getElementById('selectingFor');
  badge.textContent = selectingFor === 'player' ? 'YOUR FIGHTER' : 'ENEMY FIGHTER';
  updateSelectedDisplay();
}

function switchSelectingFor() {
  selectingFor = selectingFor === 'player' ? 'enemy' : 'player';
  updateSelectingForUI();
}

async function openPokemonPicker() {
  document.getElementById('pickerOverlay').style.display = 'flex';
  document.getElementById('pickerError').textContent = '';
  document.getElementById('pokeSearch').value = '';

  // Pre-fill from current battle
  pickerSelections.player = player ? { name: player.name, id: null, sprite: player.spriteBack || player.sprite } : null;
  pickerSelections.enemy = enemy ? { name: enemy.name, id: null, sprite: enemy.sprite } : null;

  selectingFor = 'player';
  updateSelectingForUI();

  // Load dex & render
  document.getElementById('pokedexGrid').innerHTML = '<div class="poke-loading">Loading Pokédex...</div>';
  await loadPokedex();
  filteredPokemon = [...allPokemon];
  renderPokedexGrid();
}

function closePicker() {
  document.getElementById('pickerOverlay').style.display = 'none';
}

async function confirmPokemon() {
  const ps = pickerSelections.player;
  const es = pickerSelections.enemy;

  if (!ps && !es) {
    document.getElementById('pickerError').textContent = 'Select at least one Pokémon!';
    return;
  }

  document.getElementById('pickerError').textContent = 'Loading...';

  try {
    if (ps) player = await getPokemon(ps.name);
    if (es) enemy = await getPokemon(es.name);
  } catch (e) {
    document.getElementById('pickerError').textContent = 'Could not load a Pokémon. Try again!';
    return;
  }

  document.getElementById('playerSprite').src = player.spriteBack || player.sprite;
  document.getElementById('enemySprite').src = enemy.sprite;
  updateUI();
  renderMoveButtons();
  setMoveBtnsDisabled(false);
  document.getElementById('textBox').textContent = `${enemy.name.toUpperCase()} appeared!`;
  closePicker();
}

function closeRunOverlay() {
  document.getElementById("runOverlay").style.display = "none";
}
